echo ""

MISALIGNED_COUNT=0
TOTAL_COUNT=0

find "$TEMP_DIR" -name "*.so" | while read -r lib; do
    TOTAL_COUNT=$((TOTAL_COUNT + 1))
    LIB_NAME=$(basename "$lib")
    LIB_PATH=$(echo "$lib" | sed "s|$TEMP_DIR/||")
    
    # Check alignment using readelf (if available)
    if command -v readelf &> /dev/null; then
        ALIGNMENT=$(readelf -l "$lib" 2>/dev/null | grep -A 1 "LOAD" | grep -o "0x[0-9a-f]*" | head -1)
        if [ -n "$ALIGNMENT" ]; then
            ALIGNMENT_DEC=$((ALIGNMENT))
            if [ $ALIGNMENT_DEC -lt 16384 ]; then
                echo "❌ $LIB_PATH - Alignment: $ALIGNMENT (needs 16 KB = 16384)"
                MISALIGNED_COUNT=$((MISALIGNED_COUNT + 1))
            else
                echo "✅ $LIB_PATH - Alignment: $ALIGNMENT (OK)"
            fi
        else
            echo "⚠️  $LIB_PATH - Could not determine alignment"
        fi
    else
        echo "📄 $LIB_PATH"
    fi
